// Group shifts by Employee UID
const groupedByEmployee = {};
const items = $input.all();

for (const item of items) {
  const data = item.json;
  const employeeUID = data['Employee UID'];

  if (!groupedByEmployee[employeeUID]) {
    groupedByEmployee[employeeUID] = {
      employeeUID: employeeUID,
      employeeName: data['Employee Full Name'],
      employeeEmail: data['Employee Email'],
      employeePhone: data['Employee Phone (Mobile)'],
      shifts: [],
      rowNumbers: []
    };
  }

  groupedByEmployee[employeeUID].shifts.push({
    clientName: data['Client Full Name'],
    clientAddress: data['Client Address'],
    visitStartTime: data['Visit Start Time'],
    visitEndTime: data['Visit End Time'],
    visitStartTimeOfDay: data['Visit Start Time of Day'],
    visitEndTimeOfDay: data['Visit End Time of Day'],
    visitDuration: data['Visit Scheduled Duration'],
    visitStartDate: data['Visit Start Date'],
    rowNumber: data['row_number']
  });

  groupedByEmployee[employeeUID].rowNumbers.push(data['row_number']);
}

const output = Object.values(groupedByEmployee).map(employee => {
  employee.shifts.sort((a, b) => a.visitStartTime.localeCompare(b.visitStartTime));
  return { json: employee };
});

return output;

const employeeName = $json.employeeName;
const shifts = $json.shifts;
const visitDate = shifts[0].visitStartDate;

const dateObj = new Date(visitDate);
const formattedDate = dateObj.toLocaleDateString('en-US', {
  weekday: 'long',
  month: 'long',
  day: 'numeric'
});

let shiftList = '';
for (let i = 0; i < shifts.length; i++) {
  const shift = shifts[i];
  shiftList += `\n${i + 1}. ${shift.clientName}\n`;
  shiftList += `   Time: ${shift.visitStartTimeOfDay} - ${shift.visitEndTimeOfDay}\n`;
  shiftList += `   Address: ${shift.clientAddress}`;
  if (i < shifts.length - 1) {
    shiftList += '\n';
  }
}

const message = `Hi ${employeeName},\n\nYou have ${shifts.length} shift${shifts.length > 1 ? 's' : ''} scheduled for ${formattedDate}:${shiftList}\n\nPlease arrive on time. Thank you!`;

return {
  json: {
    ...item.json,
    smsMessage: message,
    phoneNumber: $json.employeePhone
  }
};

const rowNumbers = $json.rowNumbers;
const loopIndex = $itemIndex;
const currentRowNumber = rowNumbers[loopIndex];

return {
  json: {
    rowNumber: currentRowNumber,
    status: $json.status
  }
};
